const now = new Date();
const day = now.getDay(); // 0 (Sun) to 6 (Sat)
const diffToMonday = (day + 6) % 7;
const lastMonday = new Date(now);
lastMonday.setDate(now.getDate() - diffToMonday - 7);
const lastSunday = new Date(lastMonday);
lastSunday.setDate(lastMonday.getDate() + 6);

const pad = n => n.toString().padStart(2, '0');
const format = d => `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;

return [{
  json: {
    from_date: format(lastMonday),
    to_date: format(lastSunday)
  }
}];

// Parse Mixpanel Insights response into rows.
// Adjust the series key below to match your Mixpanel event name.
const SERIES_KEY = 'WAU of Session Start'; // ← CHANGE to your event name

const series = items[0].json.series[SERIES_KEY];
const allDates = Object.keys(series['$overall']).sort().reverse();
const latestDate = allDates[0];
const prevDate = allDates[1];

const outputRows = [];

for (const [accId, accountData] of Object.entries(series)) {
  if (accId === '$overall') continue;

  // The subdomain/account key is the first non-$overall key
  const subdomainKey = Object.keys(accountData).find(k => k !== '$overall');
  const wauLatest = accountData[subdomainKey]?.[latestDate] || 0;
  const wauPrev = accountData[subdomainKey]?.[prevDate] || 0;
  const pctChange = wauPrev === 0 ? 0 : ((wauLatest - wauPrev) / wauPrev) * 100;

  outputRows.push({
    'Acc.Id': accId,
    'Acc.Subdomain': subdomainKey,
    [prevDate]: parseFloat(wauPrev.toFixed(2)),
    [latestDate]: parseFloat(wauLatest.toFixed(2)),
    'Change (%)': parseFloat(pctChange.toFixed(2))
  });
}

return outputRows.map(row => ({ json: row }));

// Filter for accounts with >10% change (absolute value).
// Adjust the threshold below to control alert sensitivity.
const THRESHOLD = 10; // percent

return items.filter(item => Math.abs(item.json['Change (%)']) > THRESHOLD);

if (items.length === 0) {
  return [];
}

const lines = items.map(item => {
  const json = item.json;
  const keys = Object.keys(json);
  const prevDate = keys[2];
  const currDate = keys[3];
  const changeValue = json['Change (%)'];
  const arrow = changeValue > 0 ? '📈' : '📉';

  return `<li>${arrow} <strong>${json['Acc.Subdomain']}</strong> (${json['Acc.Id']})<br/>
    Change: <strong>${changeValue}%</strong><br/>
    From: ${json[prevDate]} → ${json[currDate]}</li>`;
});

const currDate = Object.keys(items[0].json)[3];
const htmlMessage = `<h3>🚨 WAU Change Alert (&gt;10%)</h3>
<p>${items.length} account(s) with significant WAU changes this week:</p>
<ul>${lines.join('')}</ul>`;

return [{ json: { html: htmlMessage, subject: `WAU Alert — Week of ${currDate}` } }];
